    44	Mutations::Mutations(const MutationsProto& config, absl::Status& creation_status) {
    45	  auto request_mutations_or_error = HeaderMutations::create(config.request_mutations());
    46	  SET_AND_RETURN_IF_NOT_OK(request_mutations_or_error.status(), creation_status);
    47	  request_mutations_ = std::move(request_mutations_or_error.value());
    48	
    49	  auto response_mutations_or_error = HeaderMutations::create(config.response_mutations());
    50	  SET_AND_RETURN_IF_NOT_OK(response_mutations_or_error.status(), creation_status);
    51	  response_mutations_ = std::move(response_mutations_or_error.value());
    52	
    53	  query_query_parameter_mutations_.reserve(config.query_parameter_mutations_size());
    54	  for (const auto& mutation : config.query_parameter_mutations()) {
    55	    if (mutation.has_append()) {
    56	      if (!mutation.remove().empty()) {
    57	        creation_status =
    58	            absl::InvalidArgumentError("Only one of 'append'/'remove can be specified.");
    59	        return;
    60	      }
    61	
    62	      if (!mutation.append().has_record()) {
    63	        creation_status = absl::InvalidArgumentError("No record specified for append mutation.");
    64	        return;
    65	      }
    66	      if (!mutation.append().record().value().has_string_value()) {
    67	        creation_status =
    68	            absl::InvalidArgumentError("Only string value is allowed for record value.");
    69	        return;
    70	      }
    71	
    72	      auto value_or_error =
    73	          Formatter::FormatterImpl::create(mutation.append().record().value().string_value(), true);
    74	      SET_AND_RETURN_IF_NOT_OK(value_or_error.status(), creation_status);
    75	      query_query_parameter_mutations_.emplace_back(std::make_unique<QueryParameterMutationAppend>(
    76	          mutation.append().record().key(), std::move(value_or_error.value()),
    77	          mutation.append().action()));
    78	
    79	    } else if (!mutation.remove().empty()) {
    80	      query_query_parameter_mutations_.emplace_back(
    81	          std::make_unique<QueryParameterMutationRemove>(mutation.remove()));
    82	    } else {
    83	      creation_status = absl::InvalidArgumentError("One of 'append'/'remove' must be specified.");
    84	      return;
    85	    }
    86	  }
    87	}
