    89	void Mutations::mutateRequestHeaders(Http::RequestHeaderMap& headers,
    90	                                     const Formatter::HttpFormatterContext& context,
    91	                                     const StreamInfo::StreamInfo& stream_info) const {
    92	  request_mutations_->evaluateHeaders(headers, context, stream_info);
    93	
    94	  if (query_query_parameter_mutations_.empty() || headers.Path() == nullptr) {
    95	    return;
