   121	void HeaderMutation::maybeInitializeRouteConfigs(Http::StreamFilterCallbacks* callbacks) {
   122	  // Ensure that route configs are initialized only once and the same route configs are used
   123	  // for both decoding and encoding paths.
   124	  // An independent flag is used to ensure even at the case where the route configs is empty,
   125	  // we still won't try to initialize it again.
   126	  if (route_configs_initialized_) {
   127	    return;
   128	  }
   129	  route_configs_initialized_ = true;
   130	
   131	  // Traverse through all route configs to retrieve all available header mutations.
   132	  // `getAllPerFilterConfig` returns in ascending order of specificity (i.e., route table
   133	  // first, then virtual host, then per route).
   134	  route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteHeaderMutation>(callbacks);
   135	
   136	  // The order of returned route configs is route table first, then virtual host, then
   137	  // per route. That means the per route configs will be evaluated at the end and will
   138	  // override the more general virtual host and route table configs.
   139	  //
   140	  // So, if most_specific_header_mutations_wins is false, we need to reverse the order
   141	  // of route configs.
   142	  if (!config_->mostSpecificHeaderMutationsWins()) {
   143	    std::reverse(route_configs_.begin(), route_configs_.end());
   144	  }
   145	}
