  void mutateQueryParameter(Http::Utility::QueryParamsMulti& params,
                            const Formatter::HttpFormatterContext&,
                            const StreamInfo::StreamInfo&) const override {
    params.remove(key_);
  }

private:
  const std::string key_;
};

