namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

using ProtoConfig =
    envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection;
using PerRouteProtoConfig = envoy::extensions::filters::http::custom_header_injection::v3::
    CustomHeaderInjectionPerRoute;

/**
 * Global filter configuration. Holds pre-parsed header injection rules that apply to every
 * request/response passing through the filter chain.
 */
class FilterConfig {
public:
  FilterConfig(const ProtoConfig& config, absl::Status& creation_status);

  const Router::HeaderParser& requestHeadersParser() const { return *request_headers_parser_; }
  const Router::HeaderParser& responseHeadersParser() const { return *response_headers_parser_; }

private:
  Router::HeaderParserPtr request_headers_parser_;
  Router::HeaderParserPtr response_headers_parser_;
};
using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;

/**
 * Per-route filter configuration. Holds injection rules that override or supplement the global
 * filter configuration for a specific route, virtual host, or route table entry.
 */
class PerRouteFilterConfig : public Router::RouteSpecificFilterConfig {
public:
  PerRouteFilterConfig(const PerRouteProtoConfig& config, absl::Status& creation_status);

  const Router::HeaderParser& requestHeadersParser() const { return *request_headers_parser_; }
  const Router::HeaderParser& responseHeadersParser() const { return *response_headers_parser_; }

private:
  Router::HeaderParserPtr request_headers_parser_;
  Router::HeaderParserPtr response_headers_parser_;
};

/**
 * HTTP filter that injects configurable headers into requests and responses. Global headers are
 * applied first, followed by per-route headers in order from least specific to most specific
 * (route table → virtual host → route entry), so the most specific rule wins.
 */
class CustomHeaderInjectionFilter : public Http::PassThroughFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(FilterConfigSharedPtr config) : config_(std::move(config)) {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;

  // Http::StreamEncoderFilter
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;

private:
  // Populates route_configs_ on first call; subsequent calls are no-ops.
  void initializeRouteConfigs(Http::StreamFilterCallbacks* callbacks);

  FilterConfigSharedPtr config_;
  bool route_configs_initialized_{false};
  absl::InlinedVector<std::reference_wrapper<const PerRouteFilterConfig>, 4> route_configs_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

