#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "source/common/http/utility.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

FilterConfig::FilterConfig(const ProtoConfig& config, absl::Status& creation_status) {
  auto req_parser = Router::HeaderParser::configure(config.request_headers_to_add());
  SET_AND_RETURN_IF_NOT_OK(req_parser.status(), creation_status);
  request_headers_parser_ = std::move(req_parser.value());

  auto resp_parser = Router::HeaderParser::configure(config.response_headers_to_add());
  SET_AND_RETURN_IF_NOT_OK(resp_parser.status(), creation_status);
  response_headers_parser_ = std::move(resp_parser.value());
}

PerRouteFilterConfig::PerRouteFilterConfig(const PerRouteProtoConfig& config,
                                           absl::Status& creation_status) {
  auto req_parser = Router::HeaderParser::configure(config.request_headers_to_add());
  SET_AND_RETURN_IF_NOT_OK(req_parser.status(), creation_status);
  request_headers_parser_ = std::move(req_parser.value());

  auto resp_parser = Router::HeaderParser::configure(config.response_headers_to_add());
  SET_AND_RETURN_IF_NOT_OK(resp_parser.status(), creation_status);
  response_headers_parser_ = std::move(resp_parser.value());
}

void CustomHeaderInjectionFilter::initializeRouteConfigs(Http::StreamFilterCallbacks* callbacks) {
  if (route_configs_initialized_) {
    return;
  }
  route_configs_initialized_ = true;
  // getAllPerFilterConfig returns configs in ascending order of specificity:
  // route table → virtual host → route entry. Applying them in this order means
  // the most specific entry is evaluated last and its values win.
  route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteFilterConfig>(callbacks);
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  config_->requestHeadersParser().evaluateHeaders(headers, decoder_callbacks_->streamInfo());

  initializeRouteConfigs(decoder_callbacks_);
  for (const PerRouteFilterConfig& route_config : route_configs_) {
    route_config.requestHeadersParser().evaluateHeaders(headers,
                                                        decoder_callbacks_->streamInfo());
  }

  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  config_->responseHeadersParser().evaluateHeaders(headers, encoder_callbacks_->streamInfo());

  // If a local reply was sent before decodeHeaders ran, route configs will not yet be
  // initialized. initializeRouteConfigs is idempotent, so calling it here is safe.
  initializeRouteConfigs(encoder_callbacks_);
  for (const PerRouteFilterConfig& route_config : route_configs_) {
    route_config.responseHeadersParser().evaluateHeaders(headers,
                                                         encoder_callbacks_->streamInfo());
  }

  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

