namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

absl::StatusOr<Http::FilterFactoryCb>
CustomHeaderInjectionFactoryConfig::createFilterFactoryFromProtoTyped(
    const ProtoConfig& proto_config, const std::string&, DualInfo,
    Server::Configuration::ServerFactoryContext&) {
  absl::Status creation_status = absl::OkStatus();
  auto filter_config = std::make_shared<FilterConfig>(proto_config, creation_status);
  RETURN_IF_NOT_OK_REF(creation_status);

