FilterConfigSharedPtr makeFilterConfig(const std::string& yaml) {
  ProtoConfig proto;
  TestUtility::loadFromYaml(yaml, proto);
  absl::Status status = absl::OkStatus();
  auto config = std::make_shared<FilterConfig>(proto, status);
  EXPECT_TRUE(status.ok()) << status.message();
  return config;
}

std::shared_ptr<PerRouteFilterConfig> makePerRouteConfig(const std::string& yaml) {
  PerRouteProtoConfig proto;
  TestUtility::loadFromYaml(yaml, proto);
  absl::Status status = absl::OkStatus();
  auto config = std::make_shared<PerRouteFilterConfig>(proto, status);
  EXPECT_TRUE(status.ok()) << status.message();
  return config;
}

