TEST(CustomHeaderInjectionFactoryTest, DownstreamFactoryRegistered) {
  auto* factory =
      Registry::FactoryRegistry<Server::Configuration::NamedHttpFilterConfigFactory>::getFactory(
          "envoy.filters.http.custom_header_injection");
  ASSERT_NE(nullptr, factory);
  EXPECT_EQ("envoy.filters.http.custom_header_injection", factory->name());
}

TEST(CustomHeaderInjectionFactoryTest, UpstreamFactoryRegistered) {
  auto* factory =
      Registry::FactoryRegistry<Server::Configuration::UpstreamHttpFilterConfigFactory>::getFactory(
          "envoy.filters.http.custom_header_injection");
