}

TEST(CustomHeaderInjectionFactoryTest, CreateFilterFromValidConfig) {
  NiceMock<Server::Configuration::MockFactoryContext> context;
  auto* factory =
      Registry::FactoryRegistry<Server::Configuration::NamedHttpFilterConfigFactory>::getFactory(
          "envoy.filters.http.custom_header_injection");
  ASSERT_NE(nullptr, factory);

  const std::string yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-injected-request"
        value: "req-value"
      append_action: ADD_IF_ABSENT
    response_headers_to_add:
    - header:
        key: "x-injected-response"
        value: "resp-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  ProtoConfig proto;
  TestUtility::loadFromYaml(yaml, proto);

  auto cb_or_error = factory->createFilterFactoryFromProto(proto, "test", context);
  ASSERT_TRUE(cb_or_error.ok());

  NiceMock<Http::MockFilterChainFactoryCallbacks> filter_callbacks;
  EXPECT_CALL(filter_callbacks, addStreamFilter(_));
  cb_or_error.value()(filter_callbacks);
}

TEST(CustomHeaderInjectionFactoryTest, CreatePerRouteConfigFromValidConfig) {
  NiceMock<Server::Configuration::MockFactoryContext> context;
