// ---------------------------------------------------------------------------
// Filter behaviour: global headers only (no per-route config)
// ---------------------------------------------------------------------------

TEST(CustomHeaderInjectionFilterTest, GlobalRequestHeadersInjected) {
  const std::string yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-global-req"
        value: "global-req-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  auto config = makeFilterConfig(yaml);
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks;

  CustomHeaderInjectionFilter filter{config};
  filter.setDecoderFilterCallbacks(decoder_callbacks);
  filter.setEncoderFilterCallbacks(encoder_callbacks);

  // No per-route config.
  ON_CALL(*decoder_callbacks.route_, perFilterConfigs(_))
      .WillByDefault(Return(Router::RouteSpecificFilterConfigs{}));

  Http::TestRequestHeaderMapImpl request_headers{{":method", "GET"},
                                                 {":path", "/"},
                                                 {":scheme", "http"},
                                                 {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter.decodeHeaders(request_headers, true));
  EXPECT_EQ("global-req-value", request_headers.get_("x-global-req"));
}

