  EXPECT_EQ("global-resp-value", response_headers.get_("x-global-resp"));
}

TEST(CustomHeaderInjectionFilterTest, GlobalHeaderNotOverwrittenWhenAddIfAbsent) {
  const std::string yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-existing"
        value: "injected-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  auto config = makeFilterConfig(yaml);
