  // ADD_IF_ABSENT must not overwrite the existing value.
  EXPECT_EQ("original-value", request_headers.get_("x-existing"));
}

TEST(CustomHeaderInjectionFilterTest, GlobalHeaderOverwrittenWhenOverwriteIfExistsOrAdd) {
  const std::string yaml = R"EOF(
