// ---------------------------------------------------------------------------
// Filter behaviour: route config initialised only once
// ---------------------------------------------------------------------------

TEST(CustomHeaderInjectionFilterTest, RouteConfigsInitializedOnlyOnce) {
  const std::string global_yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-global"
        value: "global-value"
      append_action: ADD_IF_ABSENT
    response_headers_to_add:
    - header:
        key: "x-global-resp"
        value: "global-resp-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  const std::string route_yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-route"
        value: "route-value"
      append_action: ADD_IF_ABSENT
    response_headers_to_add:
    - header:
        key: "x-route-resp"
        value: "route-resp-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  auto config = makeFilterConfig(global_yaml);
  auto route_config = makePerRouteConfig(route_yaml);

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks;

  CustomHeaderInjectionFilter filter{config};
  filter.setDecoderFilterCallbacks(decoder_callbacks);
  filter.setEncoderFilterCallbacks(encoder_callbacks);

  // perFilterConfigs must be called exactly once across both decode and encode paths.
  EXPECT_CALL(*decoder_callbacks.route_, perFilterConfigs(_))
      .WillOnce(Invoke([&](absl::string_view) -> Router::RouteSpecificFilterConfigs {
        return {route_config.get()};
      }));

  Http::TestRequestHeaderMapImpl request_headers{{":method", "GET"},
                                                 {":path", "/"},
                                                 {":scheme", "http"},
                                                 {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter.decodeHeaders(request_headers, true));

  Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  // encodeHeaders must reuse the already-initialised route configs without calling
  // perFilterConfigs again on the decoder callbacks.
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter.encodeHeaders(response_headers, true));

  EXPECT_EQ("global-value", request_headers.get_("x-global"));
  EXPECT_EQ("route-value", request_headers.get_("x-route"));
  EXPECT_EQ("global-resp-value", response_headers.get_("x-global-resp"));
  EXPECT_EQ("route-resp-value", response_headers.get_("x-route-resp"));
}

// ---------------------------------------------------------------------------
// Filter behaviour: encode-only path (local reply before decodeHeaders)
// ---------------------------------------------------------------------------

TEST(CustomHeaderInjectionFilterTest, EncodeOnlyPathInitializesRouteConfigs) {
  // Simulates a local reply sent before decodeHeaders runs (e.g. auth rejection).
  const std::string global_yaml = R"EOF(
    response_headers_to_add:
    - header:
        key: "x-resp"
        value: "resp-value"
      append_action: ADD_IF_ABSENT
