// ---------------------------------------------------------------------------
// Filter behaviour: per-route headers supplement global headers
// ---------------------------------------------------------------------------

TEST(CustomHeaderInjectionFilterTest, PerRouteRequestHeadersAppliedAfterGlobal) {
  const std::string global_yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-global"
        value: "global-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  const std::string route_yaml = R"EOF(
    request_headers_to_add:
    - header:
        key: "x-route"
        value: "route-value"
      append_action: ADD_IF_ABSENT
  )EOF";

  auto config = makeFilterConfig(global_yaml);
  auto route_config = makePerRouteConfig(route_yaml);

