// Filter behaviour: encode-only path (local reply before decodeHeaders)
// ---------------------------------------------------------------------------

TEST(CustomHeaderInjectionFilterTest, EncodeOnlyPathInitializesRouteConfigs) {
  // Simulates a local reply sent before decodeHeaders runs (e.g. auth rejection).
  const std::string global_yaml = R"EOF(
    response_headers_to_add:
    - header:
        key: "x-resp"
        value: "resp-value"
