    55	/**
    56	 * HTTP filter that injects configurable headers into requests and responses. Global headers are
    57	 * applied first, followed by per-route headers in order from least specific to most specific
    58	 * (route table → virtual host → route entry), so the most specific rule wins.
    59	 */
    60	class CustomHeaderInjectionFilter : public Http::PassThroughFilter,
    61	                                    public Logger::Loggable<Logger::Id::filter> {
    62	public:
    63	  explicit CustomHeaderInjectionFilter(FilterConfigSharedPtr config) : config_(std::move(config)) {}
    64	
    65	  // Http::StreamDecoderFilter
    66	  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
    67	
    68	  // Http::StreamEncoderFilter
    69	  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
    70	
    71	private:
    72	  // Populates route_configs_ on first call; subsequent calls are no-ops.
    73	  void initializeRouteConfigs(Http::StreamFilterCallbacks* callbacks);
    74	
    75	  FilterConfigSharedPtr config_;
    76	  bool route_configs_initialized_{false};
    77	  absl::InlinedVector<std::reference_wrapper<const PerRouteFilterConfig>, 4> route_configs_;
