    30	
    31	void CustomHeaderInjectionFilter::initializeRouteConfigs(Http::StreamFilterCallbacks* callbacks) {
    32	  if (route_configs_initialized_) {
    33	    return;
    34	  }
    35	  route_configs_initialized_ = true;
    36	  // getAllPerFilterConfig returns configs in ascending order of specificity:
    37	  // route table → virtual host → route entry. Applying them in this order means
    38	  // the most specific entry is evaluated last and its values win.
    39	  route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteFilterConfig>(callbacks);
    40	}
    41	
    42	Http::FilterHeadersStatus
    43	CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
    44	  config_->requestHeadersParser().evaluateHeaders(headers, decoder_callbacks_->streamInfo());
    45	
    46	  initializeRouteConfigs(decoder_callbacks_);
    47	  for (const PerRouteFilterConfig& route_config : route_configs_) {
    48	    route_config.requestHeadersParser().evaluateHeaders(headers,
    49	                                                        decoder_callbacks_->streamInfo());
    50	  }
    51	
    52	  return Http::FilterHeadersStatus::Continue;
    53	}
    54	
    55	Http::FilterHeadersStatus
    56	CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
    57	  config_->responseHeadersParser().evaluateHeaders(headers, encoder_callbacks_->streamInfo());
    58	
    59	  // If a local reply was sent before decodeHeaders ran, route configs will not yet be
    60	  // initialized. initializeRouteConfigs is idempotent, so calling it here is safe.
    61	  initializeRouteConfigs(encoder_callbacks_);
    62	  for (const PerRouteFilterConfig& route_config : route_configs_) {
    63	    route_config.responseHeadersParser().evaluateHeaders(headers,
    64	                                                         encoder_callbacks_->streamInfo());
    65	  }
    66	
    67	  return Http::FilterHeadersStatus::Continue;
    68	}
